using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
        // To remain compatible with existing documents, restore the old property name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: id format changed from "EntityType|KeyValue" to "KeyValue" in EF Core 9.
        // To remain compatible with existing documents using "Blog|1" format, restore the old id factory.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>(b =>
        {
            b.Property(x => x.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });

        // Breaking change 3: Cosmos DB provider no longer supports sync I/O by default in EF Core 9.
        // See SyncJob.cs — all calls migrated to async equivalents.

        // Breaking change 4: HasIndex() now throws for Cosmos provider in EF Core 9 (indexes are managed by Cosmos).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

